const CONFIG = {
  userAgent: 'HelpTribeBot/1.0 (social-scraper; +https://helptribe.com)',
  minimumScore: 35,
  hotLeadScore: 80,
  crmEndpoint: 'https://dashy-production-8f23.up.railway.app/api/leads/ingest',
  excludedMarketWords: ['pakistan', 'karachi', 'lahore', 'islamabad', 'rawalpindi', 'faisalabad', 'multan', 'pkr', 'rs.']
};

const SOCIAL_SEARCHES = [
  // YouTube
  { source: 'YouTube', productHint: 'Dilivygo', query: 'restaurant POS system review 2025' },
  { source: 'YouTube', productHint: 'Marlin', query: 'property management software demo review' },
  { source: 'YouTube', productHint: 'Terro', query: 'accounting software comparison small business' },
  { source: 'YouTube', productHint: 'Haigo', query: 'hotel PMS software review comparison' },

  // Google Maps (via search)
  { source: 'Google Maps', productHint: 'Dilivygo', query: 'restaurant technology solutions Dubai' },
  { source: 'Google Maps', productHint: 'Marlin', query: 'property management companies Riyadh' },
  { source: 'Google Maps', productHint: 'Terro', query: 'accounting firms Dubai UAE' },
  { source: 'Google Maps', productHint: 'Haigo', query: 'hotel technology solutions Saudi Arabia' },

  // LinkedIn (public posts via search)
  { source: 'LinkedIn', productHint: 'Dilivygo', query: 'restaurant technology digital transformation' },
  { source: 'LinkedIn', productHint: 'Marlin', query: 'proptech property management software' },
  { source: 'LinkedIn', productHint: 'Terro', query: 'fintech accounting automation' },
  { source: 'LinkedIn', productHint: 'Haigo', query: 'hospitality technology hotel software' },

  // Facebook Groups (public)
  { source: 'Facebook', productHint: 'Dilivygo', query: 'restaurant owners group technology' },
  { source: 'Facebook', productHint: 'Marlin', query: 'landlord property management group' },
  { source: 'Facebook', productHint: 'Terro', query: 'small business accounting group' },
  { source: 'Facebook', productHint: 'Haigo', query: 'hotel management group software' },

  // Instagram
  { source: 'Instagram', productHint: 'Dilivygo', query: 'restaurant technology POS setup' },
  { source: 'Instagram', productHint: 'Haigo', query: 'hotel management system setup' },

  // Directories
  { source: 'Directory', productHint: 'Dilivygo', query: 'Capterra restaurant POS software' },
  { source: 'Directory', productHint: 'Marlin', query: 'Capterra property management software' },
  { source: 'Directory', productHint: 'Terro', query: 'Capterra accounting software UAE' },
  { source: 'Directory', productHint: 'Haigo', query: 'Capterra hotel PMS software' }
];

const PRODUCT_KEYWORDS = {
  Dilivygo: ['restaurant', 'qsr', 'fast food', 'cloud kitchen', 'ghost kitchen', 'pos', 'toast', 'square', 'lightspeed', 'doordash', 'uber eats', 'grubhub', 'deliveroo', 'talabat', 'inventory', 'food cost', 'kitchen display'],
  Marlin: ['property management', 'property manager', 'real estate', 'landlord', 'tenant', 'rent collection', 'lease', 'yardi', 'appfolio', 'buildium', 'doorloop', 'maintenance request'],
  Terro: ['accounting', 'bookkeeping', 'cfo', 'finance', 'tax', 'vat', 'corporate tax', 'zatca', 'fatoora', 'quickbooks', 'xero', 'reconciliation', 'month end', 'e-invoicing'],
  Haigo: ['hotel', 'hotels', 'hospitality', 'pms', 'front desk', 'housekeeping', 'booking engine', 'channel manager', 'cloudbeds', 'mews', 'oracle opera', 'revenue management', 'overbooking']
};

const PAIN_KEYWORDS = ['alternative', 'recommendation', 'looking for', 'switching', 'expensive', 'fees', 'bad support', 'broken', 'frustrated', 'manual', 'spreadsheet', 'does not integrate', 'outdated', 'slow', 'hard to use', 'nightmare'];

const MARKET_KEYWORDS = {
  USA: [' usa ', ' u.s.', ' united states', ' america', 'doordash', 'grubhub', 'toast pos', 'appfolio', 'yardi'],
  UK: [' uk ', ' united kingdom', ' london', ' deliveroo', 'just eat', '£'],
  Australia: [' australia', ' sydney', ' melbourne', ' menulog', ' aud '],
  UAE: [' uae', ' dubai', ' abu dhabi', ' talabat', ' careem', ' ejari', ' rera', ' aed'],
  'Saudi Arabia': [' saudi', ' ksa', ' riyadh', ' jeddah', ' hungerstation', ' zatca', ' fatoora', ' sar '],
  Qatar: [' qatar', ' doha', ' qar '],
  Kuwait: [' kuwait', ' kwd '],
  Bahrain: [' bahrain', ' bhd '],
  Oman: [' oman', ' muscat', ' omr ']
};

function cleanText(v) { return String(v || '').replace(/\s+/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').trim(); }
function includesAny(text, words) { const lower = ' ' + text.toLowerCase() + ' '; return words.filter(w => lower.includes(String(w).toLowerCase())); }
function detectMarket(text) { const lower = ' ' + text.toLowerCase() + ' '; for (const [m, words] of Object.entries(MARKET_KEYWORDS)) { if (words.some(w => lower.includes(w.toLowerCase()))) return m; } return 'Unknown / likely international'; }
function detectProduct(text, hint) { const scores = {}; for (const [p, words] of Object.entries(PRODUCT_KEYWORDS)) { scores[p] = includesAny(text, words).length; } let best = hint || 'Review'; let bestScore = scores[best] || 0; for (const [p, s] of Object.entries(scores)) { if (s > bestScore) { best = p; bestScore = s; } } return bestScore === 0 && hint ? hint : bestScore === 0 ? 'Review' : best; }
function summarizeMatches(text, product) { return { productMatches: [...new Set(includesAny(text, PRODUCT_KEYWORDS[product] || []))].slice(0, 8), painMatches: [...new Set(includesAny(text, PAIN_KEYWORDS))].slice(0, 8) }; }
function scoreLead({ text, product, market }) { const { productMatches, painMatches } = summarizeMatches(text, product); let score = 0; if (product !== 'Review') score += 20; score += Math.min(30, productMatches.length * 5); score += Math.min(30, painMatches.length * 7); if (market !== 'Unknown / likely international') score += 10; if (text.length > 250) score += 5; return Math.min(score, 100); }
function shouldExclude(text) { return CONFIG.excludedMarketWords.some(w => text.toLowerCase().includes(w)); }
function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const staticData = $getWorkflowStaticData('global');
staticData.seenSocialPosts = staticData.seenSocialPosts || {};
const now = Date.now();
for (const [id, ts] of Object.entries(staticData.seenSocialPosts)) { if (now - Number(ts) > 30 * 24 * 60 * 60 * 1000) delete staticData.seenSocialPosts[id]; }

const results = [];
let sentCount = 0, duplicateCount = 0, excludedCount = 0, belowScoreCount = 0;

for (const search of SOCIAL_SEARCHES) {
  try {
    const searchUrl = 'https://www.google.com/search?q=' + encodeURIComponent(search.query + ' site:' + search.source.toLowerCase()) + '&num=10';
    const resp = await fetch(searchUrl, { headers: { 'User-Agent': CONFIG.userAgent } });
    const html = await resp.text();

    const titleMatches = html.match(/<h3[^>]*>([^<]+)<\/h3>/gi) || [];
    const snippets = html.match(/<span[^>]*class="[^"]*"[^>]*>([^<]{20,})<\/span>/gi) || [];

    const combinedText = (titleMatches.join(' ') + ' ' + snippets.join(' ')).replace(/<[^>]+>/g, '');

    if (!combinedText || combinedText.length < 30) continue;

    const postId = search.source + '_' + search.query.replace(/[^a-z0-9]/gi, '').slice(0, 40) + '_' + now;

    if (staticData.seenSocialPosts[postId]) { duplicateCount++; continue; }

    if (shouldExclude(combinedText)) { excludedCount++; staticData.seenSocialPosts[postId] = now; continue; }

    const product = detectProduct(combinedText, search.productHint);
    const market = detectMarket(combinedText);
    const score = scoreLead({ text: combinedText, product, market });
    const matches = summarizeMatches(combinedText, product);

    if (score < CONFIG.minimumScore) { belowScoreCount++; staticData.seenSocialPosts[postId] = now; continue; }

    const lead = {
      source: search.source,
      title: titleMatches[0] ? titleMatches[0].replace(/<[^>]+>/g, '').trim() : search.query,
      selftext: combinedText.slice(0, 1000),
      url: searchUrl,
      product,
      market,
      score,
      sourceId: postId,
      productMatches: matches.productMatches,
      painMatches: matches.painMatches
    };

    try {
      const crmResp = await fetch(CONFIG.crmEndpoint, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(lead) });
      const crmData = await crmResp.json();
      results.push({ ...lead, crmStatus: crmData.status, crmDuplicate: crmData.isDuplicate });
      sentCount++;
    } catch (e) { results.push({ ...lead, crmError: e.message }); }

    staticData.seenSocialPosts[postId] = now;
    await sleep(500);
  } catch (e) { /* skip failed search */ }
  await sleep(750);
}

return [{ json: { ok: true, sentCount, duplicateCount, excludedCount, belowScoreCount, results: results.slice(0, 50), totalResults: results.length } }];

const input = $input.first().json;
const summary = 'Social Media Lead Radar run complete.

Sent to CRM: ' + input.sentCount + '
Duplicates skipped: ' + input.duplicateCount + '
Excluded markets: ' + input.excludedCount + '
Below score threshold: ' + input.belowScoreCount + '
Total results: ' + input.totalResults;
return [{ json: { ok: true, summary, ...input } }];
